    if hasattr(iterable, "keys"):
        for key in iterable.keys():
            self._update_value(key, iterable[key])
    else:
        for key, value in iterable:
            self._update_value(key, value)
    for key in kwds:
        self._update_value(key, kwds[key])

def _update_value(self, key: str, value: FeatureType):
    # If both the existing and the new value are dictionaries (or Sequences/Features backed
    # by dictionaries), merge them recursively instead of overwriting the existing value.
    if key in self:
        current_value = self[key]
        current_dict, new_dict = self._as_mergeable_dicts(current_value, value)
        if current_dict is not None and new_dict is not None:
            self._deep_merge_dicts(current_dict, new_dict)
            self[key] = current_value
            return
    self[key] = value

@staticmethod
def _as_mergeable_dicts(current_value: FeatureType, new_value: FeatureType):
    if isinstance(current_value, Sequence):
        current_value = current_value.feature
    if isinstance(new_value, Sequence):
        new_value = new_value.feature
    if isinstance(current_value, dict) and isinstance(new_value, dict):
        return current_value, new_value
    return None, None

@classmethod
def _deep_merge_dicts(cls, current_dict: dict, new_dict: dict):
    for key, value in new_dict.items():
        current_dict_, new_dict_ = cls._as_mergeable_dicts(current_dict.get(key), value)
        if current_dict_ is not None and new_dict_ is not None:
            cls._deep_merge_dicts(current_dict_, new_dict_)
        else:
            current_dict[key] = value

